external_knowledge:
; In the context of machine learning, a model's loss value is a measure of how well it is performing; 
; A lower loss value generally indicates better performance, and values less than zero may indicate overfitting or other anomalies; 
; The threshold of -0.05 might be a domain-specific indicator of acceptable performance or convergence.

sql:
SELECT run_id 
FROM training_runs 
ORDER BY run_id ASC;

SELECT average_average_discounted_return, total_num_trajectories
FROM run_metrics
WHERE run_id = 1;

external_knowledge:
; Average return refers to the average return value of a model; 
; A completed run implies a run with a status_name of 'completed';
; Model trainer refers to a user role, largely responsible for managing the training process.

sql:
SELECT average_std_return AS avg_std_return
FROM run_metrics
WHERE run_id = 1;

SELECT run_id 
FROM training_runs 
ORDER BY start_time DESC;

SELECT MAX(max_return) AS max_return_value
FROM iterations
WHERE run_id = 1;

SELECT COUNT(log_id) AS log_count
FROM run_logs
WHERE run_id = 1;

SELECT average_env_exec_time AS avg_env_exec_time
FROM run_metrics
WHERE run_id = 1;

SELECT status_name
FROM run_status
WHERE status_id = 0;
